+     */
+    struct connection_holder {
+        template <typename Callable>
+        connection_holder(Callable&& callback) : m_callback{std::forward<Callable>(callback)}
+        {
+        }
+
+        connection m_connection{connection::enabled_tag};
+        function_type m_callback;
+    };
