+     */
+    [[nodiscard]] bool empty() const EXCLUSIVE_LOCKS_REQUIRED(!m_mutex)
+    {
+        LOCK(m_mutex);
+        for (const auto& connection : m_connections) {
+            if (connection->m_connection.connected()) {
+                return false;
+            }
+        }
